import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";

function ViewApplications() {
  const [apps, setApps] = useState([]);
  const navigate = useNavigate();

  const loggedUser =
    JSON.parse(localStorage.getItem("loggedInUser")) || null;

  /* =========================
     LOAD APPLICATIONS
  ========================= */
  useEffect(() => {
    const stored =
      JSON.parse(localStorage.getItem("applications")) || [];

    if (loggedUser?.role === "employee") {
      setApps(
        stored.filter(
          (app) =>
            app.email === loggedUser.username ||
            app.empId === loggedUser.empId
        )
      );
    } else {
      setApps(stored);
    }
  }, [loggedUser]);

  /* =========================
     UPDATE STATUS
  ========================= */
  const updateStatus = (id, status) => {
    if (loggedUser?.role !== "admin") return;

    const updated = apps.map((app) =>
      app.id === id ? { ...app, status } : app
    );

    setApps(updated);
    localStorage.setItem("applications", JSON.stringify(updated));
  };

  /* =========================
     EMPLOYEE NAME
  ========================= */
  const getEmployeeName = (a) => {
    if (a.employeeName) return a.employeeName;

    const employees =
      JSON.parse(localStorage.getItem("employees")) || [];

    const emp = employees.find(
      (e) =>
        String(e.empId) === String(a.empId) ||
        String(e.email) === String(a.email)
    );

    if (!emp) return "Unknown";

    return `${emp.firstName || ""} ${emp.lastName || ""}`.trim();
  };

  /* =========================
     STATUS COLOR
  ========================= */
  const getStatusColor = (status) => {
    switch (status) {
      case "Approved":
        return "green";
      case "Rejected":
        return "red";
      case "Offer Sent":
        return "#64748b";
      default:
        return "#94a3b8";
    }
  };

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>
        {loggedUser?.role === "admin"
          ? "Job Applications (Admin)"
          : "My Job Applications"}
      </h2>

      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Employee</th>
            <th>Email</th>
            <th>Job Title</th>
            <th>Status</th>
            <th>Applied Date</th>
            {loggedUser?.role === "admin" && <th>Action</th>}
          </tr>
        </thead>

        <tbody>
          {apps.map((a, index) => (
            <tr key={a.id}>
              <td>{index + 1}</td>
              <td>{getEmployeeName(a)}</td>
              <td>{a.email}</td>
              <td>{a.jobTitle}</td>

              <td>
                <span
                  style={{
                    padding: "6px 12px",
                    borderRadius: "6px",
                    fontWeight: 600,
                    color: "white",
                    background: getStatusColor(a.status),
                  }}
                >
                  {a.status}
                </span>
              </td>

              <td>{a.appliedDate || "--"}</td>

              {loggedUser?.role === "admin" && (
                <td style={{ display: "flex", gap: "10px" }}>
                  
                  {/* PENDING */}
                  {a.status === "Pending" && (
                    <>
                      <button
                        onClick={() => updateStatus(a.id, "Approved")}
                      >
                        Approve
                      </button>
                      <button
                        onClick={() => updateStatus(a.id, "Rejected")}
                      >
                        Reject
                      </button>
                    </>
                  )}

                  {/* APPROVED */}
                  {a.status === "Approved" && (
                    <button
                      onClick={() =>
                        navigate(
                          `/dashboard/recruitment/offer-letter/${a.id}`
                        )
                      }
                    >
                      Create Offer
                    </button>
                  )}

                  {/* OFFER SENT */}
                  {a.status === "Offer Sent" && (
                    <>
                      <button
                        onClick={() =>
                          navigate(
                            `/dashboard/recruitment/offer-letter/${a.id}`
                          )
                        }
                      >
                        Edit Offer
                      </button>

                      <button
                        onClick={() =>
                          navigate(
                            `/dashboard/recruitment/offer-preview/${a.id}`
                          )
                        }
                      >
                        View Offer
                      </button>
                    </>
                  )}
                </td>
              )}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default ViewApplications;
